# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

from graphene import ObjectType, String, List, Field, Int, Float, Schema
from graphene_sqlalchemy import SQLAlchemyObjectType
from flask import Flask
from flask_graphql import GraphQLView
from sqlalchemy import create_engine, MetaData, Table

db = create_engine('sqlite:///data.db')
metadata = MetaData()
categories = Table('categories', metadata, autoload_with=db)
products = Table('products', metadata, autoload_with=db)
reviews = Table('reviews', metadata, autoload_with=db)

class CategoryType(SQLAlchemyObjectType):
    class Meta:
        model = categories
        interfaces = (String, )

class ProductType(SQLAlchemyObjectType):
    class Meta:
        model = products
        interfaces = (String, )

class ReviewType(SQLAlchemyObjectType):
    class Meta:
        model = reviews
        interfaces = (String, )

class Query(ObjectType):
    category = Field(CategoryType, 'category_id')
    products = Field(List(ProductType))
    product = Field(ProductType, 'product_id')
    reviews = Field(List(ReviewType), 'product_id')

    def resolve_products(self, info):
        return products.select()

    def resolve_category(self, info, category_id):
        return categories.select().where(categories.c.id == int(category_id)).first()

    def resolve_product(self, info, product_id):
        return products.select().where(products.c.id == int(product_id)).first()

    def resolve_reviews(self, info, product_id):
        return reviews.select().where(reviews.c.product_id == int(product_id))

app = Flask(__name__)
app.add_url_rule('/', view_func=GraphQLView.as_view('graphql', schema=Schema(query=Query)))

if __name__ == '__main__':
    app.run(debug=True)